#include <iostream>
#include <string>
#include <sstream>

// Assume Counter class is defined in the primary C++ file

std::string run_test_scenario() {
    std::stringstream ss;
    ss << "Initial count: " << Counter::getCount() << std::endl;

    Counter c1;
    ss << "After c1 created. Count: " << Counter::getCount() << std::endl;

    { 
        Counter c2;
        ss << "Object c2 created. Current count: " << Counter::getCount() << std::endl;

        Counter c3;
        ss << "Object c3 created. Current count: " << Counter::getCount() << std::endl;
    } 

    ss << "After temporary objects destroyed. Current count: " << Counter::getCount() << std::endl;

    Counter c4;
    ss << "Object c4 created. Current count: " << Counter::getCount() << std::endl;

    ss << "End of test. Final count before main exit: " << Counter::getCount() << std::endl;
    return ss.str();
}

int main() {
    std::cout << run_test_scenario();
    return 0;
}
